class Solution {
public:
    int addMinimum(string word) {
        int count = 0, state = 0;
        for (char c : word) {
            if (c == 'a') {
                if (state == 2) count += 2;
                else if (state == 1) count += 1;
                state = 1;
            } else if (c == 'b') {
                if (state == 0) count += 1;
                else if (state == 2) count += 2;
                state = 2;
            } else {
                if (state != 2) count += 2 - state;
                state = 0;
            }
        }
        return count + state;
    }
};
